    # The rubric says: no ticket must contain 'Manager Lookup' (anywhere in the ticket)
    search_term = 'Manager Lookup'
    violating_tickets = []

    # Handle various possible structures of jira_state.json
    tickets = []

    if isinstance(jira_data, list):
        tickets = jira_data
    elif isinstance(jira_data, dict):
        # Could be {"tickets": [...]}, {"issues": [...]}, or {ticket_id: {...}, ...}
