        elif "issues" in jira_data:
            tickets = jira_data["issues"] if isinstance(jira_data["issues"], list) else list(jira_data["issues"].values())
        else:
            # Might be a dict of ticket_id -> ticket_data
            for key, value in jira_data.items():
